mapper.select:
SELECT A.BZSJXJBM resourceId, COALESCE(C.PRIMARYDATASOURCECH,'未知') PRIMARYDATASOURCECH, COALESCE(C.SECONDARYDATASOURCECH,'未知') SECONDARYDATASOURCECH, COALESCE(C.PRIMARYORGANIZATIONCH,'未知') PRIMARYORGANIZATIONCH, COALESCE(C.FIRSTORGANIZATIONCH,'未知') FIRSTORGANIZATIONCH, COALESCE(C.SECONDARYORGANIZATIONCH,'未知') SECONDARYORGANIZATIONCH FROM (SELECT DISTINCT BZSJXJBM FROM DAC_ACCEPTOR_BILL
1 =1
and SCSJ_RQSJ >= #{startTime}
and SCSJ_RQSJ <= #{endTime}
and lower(SJZYMC) like lower(#{SJZYMCLike})
and lower(BZSJXJBM) like lower(#{BZSJXJBMLike})
and lower(SJJRF_DZDBH) like lower(#{SJJRF_DZDBHLike})
and DZDZTDM = #{DZDZTDM}
and DZFFDM = #{DZFFDM}
and DZZDHJ = #{DZZDHJ}
) A LEFT JOIN CLASSIFY_SOURCE_TARGET C ON A.BZSJXJBM = C.SJXJBM

SELECT * FROM (
SELECT D.*, rownum rn FROM (SELECT
RESOURCE_ID resourceId,
RESOURCE_NAME resourceName,
LINK_TYPE linkType,
CHECK_TIME checkTime,
SUM_COUNT sumCount,
SUCCESS_COUNT successCount,
SUCCESS_PERCENT successPercent,
FAILD_COUNT failCount,
CREATE_TIME createTime
FROM DAC_RECONCILIATION_ANALYSIS

	1=1

		and LINK_TYPE = #{linkType}


		and CHECK_TIME >= to_date(#{startCheckTime},'yyyy-mm-dd HH24:mi:ss')


		and CHECK_TIME <=  to_date(#{endCheckTime},'yyyy-mm-dd HH24:mi:ss')



		and lower(RESOURCE_NAME) like lower(#{resourceNameLike})



	order by


			SUM_COUNT ${sortType}


			SUCCESS_COUNT ${sortType}


			FAILD_COUNT ${sortType}


			SUCCESS_PERCENT ${sortType}


			CHECK_TIME ${sortType}



) D WHERE rownum  <=  #{pageSize}
) WHERE rn > #{pageNum}

SELECT
	RESOURCE_ID resourceId,
	RESOURCE_NAME resourceName,
	ACCESS_ACCEPTOR accAccessCount,
	ACCESS_PROVIDER proAccessCount,
	STANDARD_ACCEPTOR accStandardCount,
	STANDARD_PROVIDER proStandardCount,
	STORAGE_ACCEPTOR accStorageCount,
	STORAGE_PROVIDER proStorageCount,
	ACCESS_SAME_PERIOD accessSamePeriod,
	STANDARD_CHAIN_RATIO standardChainRatio,
	STORAGE_CHAIN_RATIO storageChainRatio,
	DATA_TIME dataTime,
	STATISTIC_TIME statisticTime,
	ALARM_STATE alarmState,
	IS_PUSH isPush,
	ACCESS_ACCEPTOR_PRE accAccessCountPre,
	ACCESS_PROVIDER_PRE proAccessCountPre
FROM
	DAC_BILL_LINK_STATISTIC

	1 = 1

		and DATA_TIME = to_date(#{dataTime},'yyyy-mm-dd hh24:mi:ss')


		and RESOURCE_NAME like concat(concat('%',#{dataName}),'%')


		and ALARM_STATE = #{alarmState}



	order by


			RESOURCE_NAME ${sortType}


			ACCESS_ACCEPTOR ${sortType}


			ACCESS_PROVIDER ${sortType}


			STANDARD_ACCEPTOR ${sortType}


			STANDARD_PROVIDER ${sortType}


			STORAGE_ACCEPTOR ${sortType}


			STORAGE_PROVIDER ${sortType}


			ACCESS_SAME_PERIOD ${sortType}


			STANDARD_CHAIN_RATIO ${sortType}


			STORAGE_CHAIN_RATIO ${sortType}

SELECT * FROM (
SELECT D.*, rownum rn from (
SELECT
SJZYMC,
BZSJXJBM,
SJJRF_DZDBH,
SJTS,
SCSJ_RQSJ,
DZDZTDM,
DZSJ_RQSJ,
XXRWBH
FROM
DAC_ACCEPTOR_BILL

	1 =1

		and SCSJ_RQSJ >= #{startTime}


		and SCSJ_RQSJ  <=  #{endTime}



		and lower(SJZYMC) like lower(#{SJZYMCLike})



		and lower(BZSJXJBM) like lower(#{BZSJXJBMLike})



		and lower(SJJRF_DZDBH) like lower(#{SJJRF_DZDBHLike})


		and DZDZTDM = #{DZDZTDM}


		and DZFFDM = #{DZFFDM}


		and DZZDHJ = #{DZZDHJ}


		and BZSJXJBM in

		#{item}



) D WHERE rownum  <=  #{pageSize}
) WHERE rn > #{pageNum}

